import kotlinx.coroutines.channels.Channel

// RENDEZVOUS (0): send suspends until receiver is ready. No buffer at all.
val rendezvous = Channel<String>(Channel.RENDEZVOUS)

// BUFFERED (default 64): send only suspends when the internal array is full.
val buffered = Channel<String>(Channel.BUFFERED)

// UNLIMITED: send never suspends; buffer grows without bound. Memory risk.
val unlimited = Channel<String>(Channel.UNLIMITED)

// CONFLATED (1): new send overwrites the unseen element. Receiver always
// gets the latest value. Equivalent to StateFlow without a default.
val conflated = Channel<String>(Channel.CONFLATED)

import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.callbackFlow
import okhttp3.sse.EventSource
import okhttp3.sse.EventSourceListener
import okhttp3.sse.EventSources

fun streamMessage(request: Request, client: OkHttpClient): Flow<ClaudeStreamEvent> =
    callbackFlow {
        val listener = object : EventSourceListener() {
            override fun onEvent(
                eventSource: EventSource,
                id: String?,
                type: String?,
                data: String
            ) {
                if (data == "[DONE]") {
                    trySend(ClaudeStreamEvent.StreamEnd)  // non-suspending — safe from callback thread
                    return
                }
                try {
                    val delta = parseTextDelta(data)  // JSON parse
                    if (delta != null) trySend(ClaudeStreamEvent.Token(delta))
                } catch (e: Exception) {
                    trySend(ClaudeStreamEvent.Error("Parse error: ${e.message}"))
                }
            }

            override fun onFailure(eventSource: EventSource, t: Throwable?, response: Response?) {
                val msg = t?.message ?: "HTTP ${response?.code}"
                trySend(ClaudeStreamEvent.Error(msg))
                close()  // closes the channel so the Flow completes
            }
        }

        val eventSource = EventSources.createFactory(client)
            .newEventSource(request, listener)

        // awaitClose runs when the Flow's collector cancels or the channel closes
        awaitClose { eventSource.cancel() }
    }

repository.streamMessage(text)
    .buffer(capacity = 32)  // producer can emit 32 tokens ahead
    .collect { event ->
        when (event) {
            is ClaudeStreamEvent.Token -> expensiveMarkdownRender(event.text)
            // …
        }
    }

// ✓ OK for location — only latest position matters
locationUpdates
    .conflate()
    .collect { updateMapMarker(it) }

// ✗ WRONG for Claude — tokens are dropped → garbled output
repository.streamMessage(text)
    .conflate()  // DO NOT do this
    .collect { event -> /* … */ }

// ✓ OK for search query debounce — only the latest keystroke triggers search
userQuery
    .collectLatest { query ->
        delay(300)
        performSearch(query)
    }

// ✗ WRONG for Claude — each new token cancels the previous update attempt
repository.streamMessage(text)
    .collectLatest { event -> /* cancelled on every token — never accumulates */ }

val logChannel = Channel<LogEntry>(Channel.BUFFERED)

// Producer 1: Claude token logger
viewModelScope.launch {
    repository.streamMessage(text).collect { event ->
        if (event is ClaudeStreamEvent.Token) {
            logChannel.send(LogEntry.Token(sessionId, event.text))
        }
    }
}

// Producer 2: UI interaction logger
viewModelScope.launch {
    uiEvents.collect { uiEvent ->
        logChannel.send(LogEntry.UiInteraction(uiEvent))
    }
}

// Single consumer: writes all entries to disk
viewModelScope.launch {
    for (entry in logChannel) {  // for-loop over channel suspends at each item
        diskLogger.write(entry)
    }
}

class ClaudeRepository(private val client: OkHttpClient) {

    // Cold flow — new SSE connection per collector
    private fun rawStream(request: Request): Flow<ClaudeStreamEvent> =
        callbackFlow {
            val listener = object : EventSourceListener() {
                override fun onEvent(es: EventSource, id: String?, type: String?, data: String) {
                    if (data == "[DONE]") { trySend(ClaudeStreamEvent.StreamEnd); return }
                    parseTextDelta(data)?.let { trySend(ClaudeStreamEvent.Token(it)) }
                }
                override fun onFailure(es: EventSource, t: Throwable?, resp: Response?) {
                    trySend(ClaudeStreamEvent.Error(t?.message ?: "HTTP ${resp?.code}"))
                    close()
                }
            }
            val es = EventSources.createFactory(client).newEventSource(request, listener)
            awaitClose { es.cancel() }
        }

    // Hot shared flow — single SSE connection, multiple collectors
    fun sharedStream(request: Request, scope: CoroutineScope): SharedFlow<ClaudeStreamEvent> =
        rawStream(request).shareIn(
            scope = scope,
            started = SharingStarted.WhileSubscribed(stopTimeoutMillis = 0),
            replay = 0
        )
}

// UNSAFE: channel not closed when job completes
val channel = Channel<String>(Channel.BUFFERED)

val producer = viewModelScope.launch {
    repeat(10) { channel.send("token $it") }
    // channel NOT closed here — consumer hangs waiting on receive()
}

val consumer = viewModelScope.launch {
    for (token in channel) {  // loops forever — never sees close
        process(token)
    }
}

// SAFE: close channel when production is done
val safeProducer = viewModelScope.launch {
    try {
        repeat(10) { channel.send("token $it") }
    } finally {
        channel.close()  // close in finally — runs even on cancellation
    }
}

import kotlinx.coroutines.channels.produce

val tokens: ReceiveChannel<String> = viewModelScope.produce {
    repeat(10) { send("token $it") }
    // channel auto-closed when block returns
}

viewModelScope.launch {
    for (token in tokens) {  // exits cleanly when produce block finishes
        process(token)
    }
}

class CallbackFlowTest {

    @Test
    fun `trySend on closed channel does not throw`() = runTest {
        val events = mutableListOf<ClaudeStreamEvent>()

        // Use a cold flow stub — simulates the same contract as callbackFlow
        val fakeFlow: Flow<ClaudeStreamEvent> = flow {
            emit(ClaudeStreamEvent.Token("Hello"))
            emit(ClaudeStreamEvent.Token(", world"))
            emit(ClaudeStreamEvent.StreamEnd)
        }

        fakeFlow.collect { events.add(it) }

        assertEquals(3, events.size)
        assertTrue(events[0] is ClaudeStreamEvent.Token)
        assertTrue(events[2] is ClaudeStreamEvent.StreamEnd)
    }

    @Test
    fun `cancellation from collector closes the channel`() = runTest {
        var awaitCloseCalled = false
        val flow: Flow<ClaudeStreamEvent> = callbackFlow {
            awaitClose { awaitCloseCalled = true }
        }

        val job = launch { flow.collect { } }
        job.cancel()
        job.join()

        assertTrue(awaitCloseCalled)
    }
}
